 99→fn track_player_movement(
100→    player: Query<&Transform, With<Player>>,
101→    mut dirty: ResMut<DirtyFlags>,
102→    mut last_tile: Local<(i32, i32)>,
103→) {
104→    let Ok(tf) = player.single() else { return };
105→    let tx = (tf.translation.x / TILE_SIZE_PX).round() as i32;
106→    let ty = (tf.translation.y / TILE_SIZE_PX).round() as i32;
107→    if tx != last_tile.0 || ty != last_tile.1 {
108→        dirty.fov_dirty = true;
109→        dirty.lighting_dirty = true;
110→        dirty.render_dirty = true;
111→        *last_tile = (tx, ty);
112→    }
113→}
