47→pub fn init_world(mut dirty: ResMut<world::DirtyFlags>, mut seed: ResMut<world::WorldSeed>, args: Res<CliArgs>) {
48→    let random_seed = args
49→        .seed
50→        .or_else(|| {
51→            std::env::var("WORLD_SEED")
52→                .ok()
53→                .and_then(|s| s.parse::<u64>().ok())
54→        })
55→        .unwrap_or_else(|| {
56→            SystemTime::now()
57→                .duration_since(UNIX_EPOCH)
58→                .map(|d| d.as_nanos() as u64)
59→                .unwrap_or(12345)
60→        });
61→
62→    seed.0 = random_seed;
63→
64→    // Mark everything as dirty at startup
65→    dirty.mark_all_dirty();
66→}
