 65→fn on_enter_overseer(
 66→    mut q_cam: Query<(&mut SmoothFollow, &Projection), With<Camera>>,
 67→    mut zoom_state: ResMut<OverseerZoomState>,
 68→    mut q_velocity: Query<&mut avian2d::prelude::LinearVelocity, With<crate::player::Player>>,
 69→) {
 70→    if let Ok((mut follow, projection)) = q_cam.single_mut() {
 71→        follow.enabled = false;
 72→        // Save current scale for zoom
 73→        if let Projection::Orthographic(ref ortho) = *projection {
 74→            zoom_state.saved_scale = Some(ortho.scale);
 75→            zoom_state.active = true;
 76→        }
 77→    }
 78→    // Stop player movement when entering Overseer
 79→    if let Ok(mut vel) = q_velocity.single_mut() {
 80→        vel.0 = Vec2::ZERO;
 81→    }
 82→}
 83→
 84→fn on_exit_overseer(
 85→    mut q_cam: Query<(&mut Transform, &mut SmoothFollow, &Projection), With<Camera>>,
 86→    q_player: Query<&GlobalTransform, With<Player>>,
 87→    mut zoom_state: ResMut<OverseerZoomState>,
 88→) {
 89→    zoom_state.active = false;
 90→    if let Ok((mut cam_tf, mut follow, _projection)) = q_cam.single_mut() {
 91→        follow.enabled = true;
 92→        follow.vel = Vec2::ZERO;
 93→        if let Ok(player_gtf) = q_player.single() {
 94→            let player_pos = player_gtf.translation().truncate();
 95→            cam_tf.translation.x = player_pos.x;
 96→            cam_tf.translation.y = player_pos.y;
 97→        }
 98→        // Don't snap zoom — set exit target for smooth transition
 99→        zoom_state.zoom_exit_target = zoom_state.saved_scale.take();
100→    }
101→}
