103→fn overseer_camera_pan(
104→    time: Res<Time>,
105→    kb: Res<ButtonInput<KeyCode>>,
106→    mouse: Res<ButtonInput<MouseButton>>,
107→    mut q_cam: Query<(&mut Transform, &Projection), With<Camera>>,
108→    mut state: ResMut<OverseerCameraState>,
109→    windows: Query<&Window>,
110→    mut dirty: ResMut<DirtyFlags>,
111→    mut last_cam_tile: Local<(i32, i32)>,
112→) {
113→    let Ok((mut cam_tf, projection)) = q_cam.single_mut() else {
114→        return;
115→    };
116→
117→    let ortho_scale = match projection {
118→        Projection::Orthographic(ref ortho) => ortho.scale,
119→        _ => 1.0,
120→    };
121→
122→    // MMB drag panning (Figma-style: drag the canvas)
123→    if mouse.pressed(MouseButton::Middle) {
124→        if let Ok(window) = windows.single() {
125→            if let Some(cursor_pos) = window.cursor_position() {
126→                if let Some(last_pos) = state.mmb_last_pos {
127→                    let delta = cursor_pos - last_pos;
128→                    // Screen Y is inverted relative to world Y
129→                    cam_tf.translation.x -= delta.x * ortho_scale;
130→                    cam_tf.translation.y += delta.y * ortho_scale;
131→                }
132→                state.mmb_last_pos = Some(cursor_pos);
133→            }
134→        }
135→    } else {
136→        state.mmb_last_pos = None;
137→    }
138→
139→    // WASD + Arrow keys for panning
140→    let mut dir = Vec2::ZERO;
141→
142→    if kb.pressed(KeyCode::KeyW) || kb.pressed(KeyCode::ArrowUp) {
143→        dir.y += 1.0;
144→    }
145→    if kb.pressed(KeyCode::KeyS) || kb.pressed(KeyCode::ArrowDown) {
146→        dir.y -= 1.0;
147→    }
148→    if kb.pressed(KeyCode::KeyA) || kb.pressed(KeyCode::ArrowLeft) {
149→        dir.x -= 1.0;
150→    }
151→    if kb.pressed(KeyCode::KeyD) || kb.pressed(KeyCode::ArrowRight) {
152→        dir.x += 1.0;
153→    }
154→
155→    if dir != Vec2::ZERO {
156→        dir = dir.normalize();
157→        let speed = state.pan_speed * time.delta_secs();
158→        cam_tf.translation.x += dir.x * speed;
159→        cam_tf.translation.y += dir.y * speed;
160→    }
161→
162→    let cam_tx = (cam_tf.translation.x / crate::world::TILE_SIZE_PX).round() as i32;
163→    let cam_ty = (cam_tf.translation.y / crate::world::TILE_SIZE_PX).round() as i32;
164→    if cam_tx != last_cam_tile.0 || cam_ty != last_cam_tile.1 {
165→        *last_cam_tile = (cam_tx, cam_ty);
166→        dirty.fov_dirty = true;
167→        dirty.lighting_dirty = true;
168→    }
169→}
