171→const MIN_Z: i32 = -100;
172→const MAX_Z: i32 = 100;
173→
174→fn overseer_scroll_z_level(
175→    mut mouse_wheel: MessageReader<MouseWheel>,
176→    mut active_z: ResMut<ActiveLayerZ>,
177→    mut dirty: ResMut<DirtyFlags>,
178→    q_ui_interactions: Query<&Interaction>,
179→) {
180→    // Don't scroll z-level when hovering/pressing UI
181→    if q_ui_interactions.iter().any(|i| *i != Interaction::None) {
182→        return;
183→    }
184→
185→    for event in mouse_wheel.read() {
186→        if event.y > 0.0 && active_z.0 < MAX_Z {
187→            active_z.0 += 1;
188→            dirty.mark_all_dirty();
189→        } else if event.y < 0.0 && active_z.0 > MIN_Z {
190→            active_z.0 -= 1;
191→            dirty.mark_all_dirty();
192→        }
193→    }
194→}
