196→fn overseer_camera_z_level(
197→    kb: Res<ButtonInput<KeyCode>>,
198→    mut active_z: ResMut<ActiveLayerZ>,
199→    mut dirty: ResMut<DirtyFlags>,
200→) {
201→    let mut changed = false;
202→
203→    if kb.just_pressed(KeyCode::PageUp) && active_z.0 < MAX_Z {
204→        active_z.0 += 1;
205→        changed = true;
206→    }
207→    if kb.just_pressed(KeyCode::PageDown) && active_z.0 > MIN_Z {
208→        active_z.0 -= 1;
209→        changed = true;
210→    }
211→
212→    if changed {
213→        dirty.mark_all_dirty();
214→    }
215→}
