217→/// Show units below or at the active z-level with depth-based shading.
218→/// Units above the active z-level or more than MAX_DEPTH below are invisible.
219→fn update_unit_z_depth_shading(
220→    active_z: Res<ActiveLayerZ>,
221→    view_override: Res<crate::world::ViewLevelOverride>,
222→    world_map: Res<crate::world::WorldMap>,
223→    registry: Res<crate::world::BlockRegistry>,
224→    mut q_units: Query<(&UnitZ, &Transform, &mut Sprite, Option<&Player>)>,
225→    vis_maps: Res<crate::fov::visibility::VisibilityMaps>,
226→) {
227→    const DEPTH_FACTOR: f32 = 0.7;
228→    const MAX_DEPTH: i32 = 3;
229→
230→    let view_z = view_override.0.unwrap_or(active_z.0);
231→    let fov_z = vis_maps.last_computed_z.unwrap_or(view_z);
232→
233→    for (unit_z, tf, mut sprite, player) in &mut q_units {
234→        let dz = view_z - unit_z.0; // positive = unit is BELOW us
235→        if dz < 0 || dz > MAX_DEPTH {
236→            // Unit is above view_z (behind ceiling) or too deep → invisible
237→            if player.is_some() && view_override.0.is_some() {
238→                sprite.color = Color::srgba(1.0, 1.0, 1.0, 0.3);
239→            } else {
240→                sprite.color = Color::srgba(1.0, 1.0, 1.0, 0.0);
241→            }
242→        } else if dz == 0 {
243→            // On current level — check FOV
244→            let tx = (tf.translation.x / crate::world::TILE_SIZE_PX).round() as i32;
245→            let ty = (tf.translation.y / crate::world::TILE_SIZE_PX).round() as i32;
246→            let visible = vis_maps.is_visible(tx, ty, fov_z);
247→            if visible {
248→                sprite.color = Color::WHITE;
249→            } else {
250→                sprite.color = Color::srgba(1.0, 1.0, 1.0, 0.0);
251→            }
252→        } else {
253→            // Unit below view level — check if blocked by solid terrain
254→            let tx = (tf.translation.x / crate::world::TILE_SIZE_PX).round() as i32;
255→            let ty = (tf.translation.y / crate::world::TILE_SIZE_PX).round() as i32;
256→            let blocked = (1..=dz).any(|d| {
257→                world_map.get_block(tx, ty, unit_z.0 + d)
258→                    .map(|b| registry.vision_transmittance(b.block_type) == 0.0)
259→                    .unwrap_or(false)
260→            });
261→            if blocked {
262→                if player.is_some() && view_override.0.is_some() {
263→                    sprite.color = Color::srgba(1.0, 1.0, 1.0, 0.3);
264→                } else {
265→                    sprite.color = Color::srgba(1.0, 1.0, 1.0, 0.0);
266→                }
267→            } else {
268→                let factor = DEPTH_FACTOR.powi(dz);
269→                sprite.color = Color::srgba(factor, factor, factor, factor.max(0.2));
270→            }
271→        }
272→    }
273→}
274→
275→fn quick_peek_camera(
276→    mut peek: ResMut<QuickPeekState>,
277→    mut zoom_state: ResMut<OverseerZoomState>,
278→    mut q_cam: Query<&mut Projection, With<Camera>>,
279→    time: Res<Time>,
280→) {
281→    let Ok(mut projection) = q_cam.single_mut() else { return };
282→    let Projection::Orthographic(ref mut ortho) = *projection else { return };
283→
284→    if peek.active {
285→        if peek.saved_camera_scale.is_none() {
286→            peek.saved_camera_scale = Some(ortho.scale);
287→        }
288→        let saved = peek.saved_camera_scale.unwrap_or(1.0);
289→        let target = saved * QUICK_PEEK_ZOOM;
290→        ortho.scale += (target - ortho.scale) * (5.0 * time.delta_secs()).min(1.0);
291→    } else if zoom_state.active {
292→        let saved = zoom_state.saved_scale.unwrap_or(ortho.scale);
293→        let target = saved * QUICK_PEEK_ZOOM;
294→        ortho.scale += (target - ortho.scale) * (5.0 * time.delta_secs()).min(1.0);
295→    } else if let Some(target) = zoom_state.zoom_exit_target {
296→        // Smooth return from Overseer zoom
297→        ortho.scale += (target - ortho.scale) * (6.0 * time.delta_secs()).min(1.0);
298→        if (ortho.scale - target).abs() < 0.01 {
299→            ortho.scale = target;
300→            zoom_state.zoom_exit_target = None;
301→        }
302→    } else if let Some(s) = peek.saved_camera_scale {
303→        // Returning to normal from peek
304→        ortho.scale += (s - ortho.scale) * (8.0 * time.delta_secs()).min(1.0);
305→        if (ortho.scale - s).abs() < 0.01 {
306→            ortho.scale = s;
307→            peek.saved_camera_scale = None;
308→        }
309→    }
310→}
