 52→/// Find the entity with the fewest queued commands, closest to target.
 53→/// Uses a disjoint (Without<Selected>) fallback query to avoid Bevy query conflicts.
 54→fn find_nearest_free_unit(
 55→    q_find: &Query<(Entity, &Transform, &UnitZ, &mut UnitCommandQueue, Option<&mut LinearVelocity>), (With<Selectable>, Without<Selected>)>,
 56→    target: IVec3,
 57→) -> Option<Entity> {
 58→    let mut best: Option<(Entity, f32, usize)> = None;
 59→    for (entity, tf, uz, queue, _) in q_find.iter() {
 60→        let dx = (tf.translation.x / TILE_SIZE_PX).round() as i32 - target.x;
 61→        let dy = (tf.translation.y / TILE_SIZE_PX).round() as i32 - target.y;
 62→        let dz = uz.0 - target.z;
 63→        let dist = (dx * dx + dy * dy + dz * dz * 4) as f32;
 64→        let q_len = queue.len();
 65→        let better = match &best {
 66→            None => true,
 67→            Some((_, best_dist, best_q)) => {
 68→                q_len < *best_q || (q_len == *best_q && dist < *best_dist)
 69→            }
 70→        };
 71→        if better {
 72→            best = Some((entity, dist, q_len));
 73→        }
 74→    }
 75→    best.map(|(e, _, _)| e)
 76→}
