 78→fn handle_rmb_command(
 79→    mut commands: Commands,
 80→    mouse: Res<ButtonInput<MouseButton>>,
 81→    kb: Res<ButtonInput<KeyCode>>,
 82→    cursor: Res<OverseerCursor>,
 83→    tool_mode: Res<State<OverseerToolMode>>,
 84→    // Selected units: mutable, includes position for focused-unit lookup
 85→    mut q_selected_mut: Query<
 86→        (Entity, &Transform, &UnitZ, &mut UnitCommandQueue, Option<&mut LinearVelocity>),
 87→        With<Selected>,
 88→    >,
 89→    // Fallback units: mutable, disjoint from q_selected_mut via Without<Selected>
 90→    mut q_fallback_mut: Query<
 91→        (Entity, &Transform, &UnitZ, &mut UnitCommandQueue, Option<&mut LinearVelocity>),
 92→        (With<Selectable>, Without<Selected>),
 93→    >,
 94→    mut q_companions: Query<&mut Companion>,
 95→    mut one_shot: ResMut<super::mode::OneShotCursor>,
 96→    mut meshes: ResMut<Assets<Mesh>>,
 97→    mut materials: ResMut<Assets<ColorMaterial>>,
 98→    inventory_ui: Res<InventoryUiState>,
 99→    focused: Res<FocusedUnit>,
100→    mut panel_state: ResMut<crate::companions::panel::CompanionPanelState>,
101→    q_ui_interactions: Query<&Interaction>,
102→) {
103→    if inventory_ui.open {
104→        return;
105→    }
106→    // UI hover/press blocks world interaction
107→    if q_ui_interactions.iter().any(|i| *i != Interaction::None) { return; }
108→    if !mouse.just_pressed(MouseButton::Right) {
109→        return;
110→    }
111→
112→    // One-shot cursor mode: command goes to specific target, then deactivate
113→    if one_shot.active {
114→        if let Some(target_entity) = one_shot.target {
115→            let command = match &cursor.action {
116→                SmartAction::MoveTo(pos) => UnitCommand::MoveTo(*pos),
117→                SmartAction::Build(pos, item_id) => UnitCommand::Build(*pos, *item_id),
118→                SmartAction::Demolish(pos) => UnitCommand::Demolish(*pos),
119→                SmartAction::Pickup(entity) => UnitCommand::Pickup(*entity),
120→                SmartAction::FollowUnit(target) => {
121→                    if let Ok(mut companion) = q_companions.get_mut(target_entity) {
122→                        companion.behavior = CompanionBehavior::FollowEntity(*target);
123→                    }
124→                    if let Some(t) = one_shot.target { commands.entity(t).remove::<Selected>(); }
125→                    one_shot.active = false;
126→                    one_shot.target = None;
127→                    return;
128→                }
129→                SmartAction::None => {
130→                    if let Some(t) = one_shot.target { commands.entity(t).remove::<Selected>(); }
131→                    one_shot.active = false;
132→                    one_shot.target = None;
133→                    return;
134→                }
135→            };
136→
137→            let shift = kb.pressed(KeyCode::ShiftLeft) || kb.pressed(KeyCode::ShiftRight);
138→            if let Ok((_, _, _, mut queue, velocity)) = q_fallback_mut.get_mut(target_entity) {
139→                if !shift {
140→                    clear_unit_commands(target_entity, &mut queue, velocity, &mut commands);
141→                }
142→                queue.push(command.clone(), None);
143→                station_companion(target_entity, &mut q_companions);
144→            } else if let Ok((_, _, _, mut queue, velocity)) = q_selected_mut.get_mut(target_entity) {
145→                if !shift {
146→                    clear_unit_commands(target_entity, &mut queue, velocity, &mut commands);
147→                }
148→                queue.push(command.clone(), None);
149→                station_companion(target_entity, &mut q_companions);
150→            }

