 32→impl UnitCommandQueue {
 33→    pub fn push(&mut self, cmd: UnitCommand, task_id: Option<TaskId>) {
 34→        self.commands.push_back(cmd);
 35→        self.task_ids.push_back(task_id);
 36→    }
