 38→    pub fn pop_front(&mut self) -> Option<(UnitCommand, Option<TaskId>)> {
 39→        let cmd = self.commands.pop_front()?;
 40→        let task_id = self.task_ids.pop_front().flatten();
 41→        Some((cmd, task_id))
 42→    }
