 44→    pub fn front(&self) -> Option<&UnitCommand> {
 45→        self.commands.front()
 46→    }
 47→
 48→    /// Clear all commands, returning any orphaned TaskIds.
 49→    pub fn clear(&mut self) -> Vec<TaskId> {
 50→        self.commands.clear();
 51→        let orphans: Vec<TaskId> = self.task_ids.drain(..).flatten().collect();
 52→        orphans
 53→    }
 54→
 55→    /// Retain commands matching predicate, returning removed TaskIds.
 56→    pub fn retain(&mut self, mut f: impl FnMut(&UnitCommand) -> bool) -> Vec<TaskId> {
 57→        let mut removed_task_ids = Vec::new();
 58→        let mut new_commands = VecDeque::new();
 59→        let mut new_task_ids = VecDeque::new();
 60→
 61→        while let Some(cmd) = self.commands.pop_front() {
 62→            let tid = self.task_ids.pop_front().flatten();
 63→            if f(&cmd) {
 64→                new_commands.push_back(cmd);
 65→                new_task_ids.push_back(tid);
 66→            } else if let Some(id) = tid {
 67→                removed_task_ids.push(id);
 68→            }
 69→        }
 70→
 71→        self.commands = new_commands;
 72→        self.task_ids = new_task_ids;
 73→        removed_task_ids
 74→    }
 75→
 76→    pub fn iter(&self) -> impl Iterator<Item = &UnitCommand> {
 77→        self.commands.iter()
 78→    }
 79→
 80→    pub fn is_empty(&self) -> bool {
 81→        self.commands.is_empty()
 82→    }
 83→
 84→    pub fn len(&self) -> usize {
 85→        self.commands.len()
 86→    }
 87→
 88→    /// Remove command at index, returning its TaskId if any.
 89→    pub fn remove_at(&mut self, idx: usize) -> Option<TaskId> {
 90→        if idx < self.commands.len() {
 91→            self.commands.remove(idx);
 92→            self.task_ids.remove(idx).flatten()
 93→        } else {
 94→            None
 95→        }
 96→    }
 97→}
