103→/// Pure function: determine what action to take at cursor position.
104→///
105→/// Priority (in Auto mode):
106→/// 0. Companion unit at tile → FollowUnit
107→/// 1. WorldItem on tile → Pickup
108→/// 2. Solid block at tile (blocks_movement) → Demolish
109→/// 3. Empty tile + held block item → Build
110→/// 4. Walkable surface below → MoveTo
111→/// 5. None
112→pub fn resolve_smart_action(
113→    ctx: &CursorContext,
114→    registry: &BlockRegistry,
115→) -> SmartAction {
116→    let tile = ctx.tile;
117→
118→    match ctx.tool_mode {
119→        OverseerToolMode::ForceBuild => {
120→            // Force build if we have a block item
121→            if let Some(item_id) = ctx.held_block_item {
122→                return SmartAction::Build(tile, item_id);
123→            }
124→            return SmartAction::None;
125→        }
126→        OverseerToolMode::ForceDemolish => {
127→            // Force demolish if block is mineable
128→            if let Some(bt) = ctx.block_at_tile {
129→                if registry.is_mineable(bt) {
130→                    return SmartAction::Demolish(tile);
131→                }
132→            }
133→            return SmartAction::None;
134→        }
135→        OverseerToolMode::ForcePickup => {
136→            // Force pickup if there is a world item under cursor
137→            if let Some(entity) = ctx.world_item {
138→                return SmartAction::Pickup(entity);
139→            }
140→            return SmartAction::None;
141→        }
142→        OverseerToolMode::ForceCancel => {
143→            return SmartAction::None;
144→        }
145→        OverseerToolMode::Auto => {
146→            // Smart resolution below
147→        }
148→    }
149→
150→    // 0. Companion unit at tile + in Auto mode → FollowUnit
151→    if let Some(entity) = ctx.companion_at_tile {
152→        return SmartAction::FollowUnit(entity);
153→    }
154→
155→    // 1. World item on tile → Pickup
156→    if let Some(entity) = ctx.world_item {
157→        return SmartAction::Pickup(entity);
158→    }
159→
160→    // 2. Mineable block at tile → Demolish
161→    if let Some(bt) = ctx.block_at_tile {
162→        if registry.is_mineable(bt) {
163→            return SmartAction::Demolish(tile);
164→        }
165→    }
166→
167→    // 3. Empty tile + held block → Build
168→    let tile_is_empty = match ctx.block_at_tile {
169→        None | Some(BlockType { 0: 0 }) => true, // None or AIR (id=0)
170→        _ => false,
171→    };
172→    if tile_is_empty {
173→        if let Some(item_id) = ctx.held_block_item {
174→            return SmartAction::Build(tile, item_id);
175→        }
176→    }
177→
178→    // 4. Has support below → MoveTo
179→    if let Some(bt) = ctx.block_below {
180→        if registry.supports_standing(bt) {
181→            return SmartAction::MoveTo(tile);
182→        }
183→    }
184→
185→    SmartAction::None
186→}
