  1→//! Chunk storage for world data.
  2→//!
  3→//! A chunk is a CHUNK_SIZE x CHUNK_SIZE grid of blocks with optional surface covers.
  4→
  5→use super::block::BlockVolume;
  6→use super::surface::{CeilingCoverId, FloorCoverId};
  7→use std::collections::HashMap;
  8→
  9→pub const CHUNK_SIZE: usize = 32;
 10→pub const TILE_SIZE_PX: f32 = 32.0;
 11→
 12→#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
 13→pub enum ChunkState {
 14→    #[default]
 15→    Unloaded,
 16→    Generated,
 17→}
 18→
 19→/// A chunk of the world map.
 20→///
 21→/// Contains:
 22→/// - Dense storage for blocks (every cell has a block, default is Air)
 23→/// - Sparse storage for floor covers (most cells don't have covers)
 24→/// - Sparse storage for ceiling covers (placeholder for future)
 25→#[derive(Debug, Clone)]
 26→pub struct Chunk {
 27→    /// Dense storage: blocks (BlockVolume for each cell)
 28→    blocks: Vec<BlockVolume>,
 29→
 30→    /// Sparse storage for floor covers
 31→    floor_covers: HashMap<(u8, u8), FloorCoverId>,
 32→
 33→    /// Sparse storage for ceiling covers (placeholder)
 34→    ceiling_covers: HashMap<(u8, u8), CeilingCoverId>,
 35→
 36→    pub state: ChunkState,
 37→}
 38→
 39→impl Default for Chunk {
 40→    fn default() -> Self {
 41→        Self::new()
 42→    }
 43→}
 44→
 45→impl Chunk {
 46→    pub fn new() -> Self {
 47→        Self {
 48→            blocks: vec![BlockVolume::default(); CHUNK_SIZE * CHUNK_SIZE],
 49→            floor_covers: HashMap::new(),
 50→            ceiling_covers: HashMap::new(),
 51→            state: ChunkState::Unloaded,
 52→        }
 53→    }
 54→
 55→    /// Create a chunk with pre-filled blocks
 56→    pub fn with_blocks(blocks: Vec<BlockVolume>) -> Self {
 57→        assert_eq!(blocks.len(), CHUNK_SIZE * CHUNK_SIZE);
 58→        Self {
 59→            blocks,
 60→            floor_covers: HashMap::new(),
 61→            ceiling_covers: HashMap::new(),
 62→            state: ChunkState::Generated,
 63→        }
 64→    }
 65→
 66→    #[inline]
 67→    fn index(local_x: usize, local_y: usize) -> usize {
 68→        local_y * CHUNK_SIZE + local_x
 69→    }
 70→
 71→    #[inline]
 72→    fn local_key(local_x: usize, local_y: usize) -> (u8, u8) {
 73→        (local_x as u8, local_y as u8)
 74→    }
 75→
 76→    // === Block access ===
 77→
 78→    /// Get block at position
 79→    pub fn get_block(&self, local_x: usize, local_y: usize) -> Option<BlockVolume> {
 80→        if local_x >= CHUNK_SIZE || local_y >= CHUNK_SIZE {
 81→            return None;
 82→        }
 83→        self.blocks.get(Self::index(local_x, local_y)).copied()
 84→    }
 85→
 86→    /// Set block at position
 87→    pub fn set_block(&mut self, local_x: usize, local_y: usize, block: BlockVolume) {
 88→        if local_x < CHUNK_SIZE && local_y < CHUNK_SIZE {
 89→            self.blocks[Self::index(local_x, local_y)] = block;
 90→        }
 91→    }
 92→
 93→    /// Iterate over blocks
 94→    pub fn iter_blocks(&self) -> impl Iterator<Item = (usize, usize, BlockVolume)> + '_ {
 95→        self.blocks.iter().enumerate().map(|(i, &block)| {
 96→            let x = i % CHUNK_SIZE;
 97→            let y = i / CHUNK_SIZE;
 98→            (x, y, block)
 99→        })
100→    }

