  8→/// <reference path="./virtual.d.ts" />
  9→
 10→import mdx from '@astrojs/mdx';
 11→import type { AstroIntegration } from 'astro';
 12→import { AstroError } from 'astro/errors';
 13→import {
 14→	starlightRehypePlugins,
 15→	starlightRemarkPlugins,
 16→	type RemarkRehypePluginOptions,
 17→} from './integrations/remark-rehype';
 18→import { starlightDirectivesRestorationIntegration } from './integrations/asides';
 19→import { starlightExpressiveCode } from './integrations/expressive-code/index';
 20→import { starlightPagefind } from './integrations/pagefind';
 21→import { starlightSitemap } from './integrations/sitemap';
 22→import { vitePluginStarlightCssLayerOrder } from './integrations/vite-layer-order';
 23→import { vitePluginStarlightUserConfig } from './integrations/virtual-user-config';
 24→import {
 25→	injectPluginTranslationsTypes,
 26→	runPlugins,
 27→	type PluginTranslations,
 28→	type StarlightUserConfigWithPlugins,
 29→} from './utils/plugins';
 30→import { processI18nConfig } from './utils/i18n';
 31→import type { StarlightConfig } from './types';
 32→
 33→export default function StarlightIntegration(
 34→	userOpts: StarlightUserConfigWithPlugins
 35→): AstroIntegration {
 36→	if (typeof userOpts !== 'object' || userOpts === null || Array.isArray(userOpts))
 37→		throw new AstroError(
 38→			'Invalid config passed to starlight integration',
 39→			`The Starlight integration expects a configuration object with at least a \`title\` property.\n\n` +
 40→				`See more details in the [Starlight configuration reference](https://starlight.astro.build/reference/configuration/)\n`
 41→		);
 42→	const { plugins, ...opts } = userOpts;
 43→	let userConfig: StarlightConfig;
 44→	let pluginTranslations: PluginTranslations = {};
 45→	return {
 46→		name: '@astrojs/starlight',
 47→		hooks: {
 48→			'astro:config:setup': async ({
 49→				addMiddleware,
 50→				command,
 51→				config,
 52→				injectRoute,
 53→				isRestart,
 54→				logger,
 55→				updateConfig,
 56→			}) => {
 57→				// Run plugins to get the updated configuration and any extra Astro integrations to load.
 58→				const pluginResult = await runPlugins(opts, plugins, {
 59→					command,
 60→					config,
 61→					isRestart,
 62→					logger,
 63→				});
 64→				// Process the Astro and Starlight configurations for i18n and translations.
 65→				const { astroI18nConfig, starlightConfig } = processI18nConfig(
 66→					pluginResult.starlightConfig,
 67→					config.i18n
 68→				);
 69→
 70→				const { integrations, useTranslations, absolutePathToLang } = pluginResult;
 71→				pluginTranslations = pluginResult.pluginTranslations;
 72→				userConfig = starlightConfig;
 73→
 74→				addMiddleware({ entrypoint: '@astrojs/starlight/locals', order: 'pre' });
 75→
 76→				if (!starlightConfig.disable404Route) {
 77→					injectRoute({
 78→						pattern: '404',
 79→						entrypoint: starlightConfig.prerender
 80→							? '@astrojs/starlight/routes/static/404.astro'
 81→							: '@astrojs/starlight/routes/ssr/404.astro',
 82→						prerender: starlightConfig.prerender,
 83→					});
 84→				}
 85→				injectRoute({
 86→					pattern: '[...slug]',
 87→					entrypoint: starlightConfig.prerender
 88→						? '@astrojs/starlight/routes/static/index.astro'
 89→						: '@astrojs/starlight/routes/ssr/index.astro',
 90→					prerender: starlightConfig.prerender,
 91→				});
 92→
 93→				// Add built-in integrations only if they are not already added by the user through the
 94→				// config or by a plugin.
 95→				const allIntegrations = [...config.integrations, ...integrations];
 96→				if (!allIntegrations.find(({ name }) => name === 'astro-expressive-code')) {
 97→					integrations.push(
 98→						...starlightExpressiveCode({ astroConfig: config, starlightConfig, useTranslations })
 99→					);
100→				}
101→				if (!allIntegrations.find(({ name }) => name === '@astrojs/sitemap')) {
102→					integrations.push(starlightSitemap(starlightConfig));
103→				}
104→				if (!allIntegrations.find(({ name }) => name === '@astrojs/mdx')) {
105→					integrations.push(mdx({ optimize: true }));
106→				}
107→
108→				// Add Starlight directives restoration integration at the end of the list so that remark
109→				// plugins injected by Starlight plugins through Astro integrations can handle text and
110→				// leaf directives before they are transformed back to their original form.
111→				integrations.push(starlightDirectivesRestorationIntegration());
112→
113→				// Add integrations immediately after Starlight in the config array.
114→				// e.g. if a user has `integrations: [starlight(), tailwind()]`, then the order will be
115→				// `[starlight(), expressiveCode(), sitemap(), mdx(), tailwind()]`.
116→				// This ensures users can add integrations before/after Starlight and we respect that order.
117→				const selfIndex = config.integrations.findIndex((i) => i.name === '@astrojs/starlight');
118→				config.integrations.splice(selfIndex + 1, 0, ...integrations);
119→
120→				const remarkRehypeOptions: RemarkRehypePluginOptions = {
121→					starlightConfig,
122→					astroConfig: config,
123→					useTranslations,
124→					absolutePathToLang,
125→				};
126→
127→				// TODO: refactor once there is a reliable way to detect non-Node.js compatible
128→				// environments, rather than relying on the presence of specific adapters/integrations.
129→				const isCloudflareEnv =
130→					config.adapter?.name === '@astrojs/cloudflare' ||
131→					config.integrations.some(({ name }) => name === '@astrojs/cloudflare');
132→				const isNodeCompatibleEnv = !isCloudflareEnv;
133→
134→				updateConfig({
135→					vite: {
136→						plugins: [
137→							vitePluginStarlightCssLayerOrder(),
138→							vitePluginStarlightUserConfig(
139→								{ command, isNodeCompatibleEnv },
140→								starlightConfig,
141→								config,
142→								pluginTranslations
143→							),
144→						],
145→						ssr: isNodeCompatibleEnv
146→							? {}
147→							: {
148→									optimizeDeps: {
149→										include: [
150→											// Prebundle some dependencies for non-Node.js compatible environments to
151→											// speed up dev server start time and prevent restarts.
152→											'@astrojs/cloudflare/entrypoints/server',
153→											'@astrojs/starlight>i18next',
154→											'@astrojs/starlight>js-yaml',
155→											'@astrojs/starlight>klona/lite',
156→											// TODO: once Expressive Code is refactored/fixed, remove this workaround for
157→											// Expressive Code relying on CJS dependencies like postcss not compatible
158→											// with non-Node.js compatible environments like Cloudflare.
159→											'@astrojs/starlight>astro-expressive-code/components',
160→											'@astrojs/starlight>astro-expressive-code>hast-util-select',
161→											'@astrojs/starlight>astro-expressive-code>rehype',
162→											'@astrojs/starlight>astro-expressive-code>unist-util-visit',
163→											'@astrojs/starlight>astro-expressive-code>rehype-format',
164→											'@astrojs/starlight>astro-expressive-code>hastscript',
165→											'@astrojs/starlight>astro-expressive-code>hast-util-from-html',
166→											'@astrojs/starlight>astro-expressive-code>hast-util-to-string',
167→											'@astrojs/starlight>astro-expressive-code>@expressive-code/core>postcss',
168→										],
169→									},
170→								},
171→					},
172→					markdown: {
173→						remarkPlugins: [...starlightRemarkPlugins(remarkRehypeOptions)],
174→						rehypePlugins: [...starlightRehypePlugins(remarkRehypeOptions)],
175→					},
176→					scopedStyleStrategy: 'where',
177→					// If not already configured, default to prefetching all links on hover.
178→					prefetch: config.prefetch ?? { prefetchAll: true },
179→					i18n: astroI18nConfig,
180→				});
181→			},
182→
183→			'astro:config:done': ({ injectTypes }) => {
184→				injectPluginTranslationsTypes(pluginTranslations, injectTypes);
185→			},
186→
187→			'astro:build:done': async (options) => {
188→				if (!userConfig.pagefind) return;
189→				return starlightPagefind(options);
190→			},
191→		},
192→	};
193→}
