@import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:ital,wght@0,400;0,600;0,700;1,400&family=IBM+Plex+Mono:wght@400;600&display=swap');

:root {
  --sl-font: 'IBM Plex Sans', sans-serif;
  --sl-font-mono: 'IBM Plex Mono', monospace;

  --sl-color-accent-low: #1a3a2a;
  --sl-color-accent: #4c9a6e;
  --sl-color-accent-high: #b8e6c8;

  --sl-color-white: #e8f0ec;
  --sl-color-gray-1: #c4d4ca;
  --sl-color-gray-2: #94a89a;
  --sl-color-gray-3: #6b8072;
  --sl-color-gray-4: #455850;
  --sl-color-gray-5: #2a3832;
  --sl-color-gray-6: #1e2b26;
  --sl-color-gray-7: #141e1a;
  --sl-color-black: #0e1612;
}

:root[data-theme='light'] {
  --sl-color-accent-low: #d4f0df;
  --sl-color-accent: #2d7a4f;
  --sl-color-accent-high: #143824;

  --sl-color-white: #141e1a;
  --sl-color-gray-1: #2a3832;
  --sl-color-gray-2: #455850;
  --sl-color-gray-3: #6b8072;
  --sl-color-gray-4: #94a89a;
  --sl-color-gray-5: #c4d4ca;
  --sl-color-gray-6: #e4ede8;
  --sl-color-gray-7: #f2f7f4;
  --sl-color-black: #f8fbf9;
}

/* Terminal-style code blocks */
pre {
  border: 1px solid var(--sl-color-gray-5);
}

